SELECT TOP 1 SUM(NS.[DAILY_DELIVERED]) AS DELIVERED,
	SUM(NS.[DAILY_SENT]) AS SENT 
FROM [NOTIFICATION_STATISTICS] NS 
WHERE NS.[IsDeleted] = 0 
